// /frontend/src/components/Radar.jsx
import React, { useEffect, useMemo, useRef, useState } from "react";
import { MapContainer, TileLayer } from "react-leaflet";
import "leaflet/dist/leaflet.css";

function clamp(n, min, max) { return Math.max(min, Math.min(max, n)); }

export default function Radar({
  center = [33.7490, -84.3880],
  zoom = 5,
  height = 260,
  className = "",
  refreshSeconds = 60,
}) {
  const alive = useRef(true);
  const mapRef = useRef(null);

  const [frameTime, setFrameTime] = useState(null);
  const [tilesLoaded, setTilesLoaded] = useState(false);
  const [tileError, setTileError] = useState(false);
  const [controlsOn, setControlsOn] = useState(false); // mobile toggle
  const [hovering, setHovering] = useState(false);     // desktop hover

  // Guard center/zoom
  const safeCenter = useMemo(() => {
    let [lat, lon] = Array.isArray(center) ? center : [33.7490, -84.3880];
    lat = Number.isFinite(lat) ? clamp(lat, -85, 85) : 33.7490;
    lon = Number.isFinite(lon) ? clamp(lon, -180, 180) : -84.3880;
    return [lat, lon];
  }, [center]);
  const safeZoom = useMemo(() => (Number.isFinite(zoom) ? clamp(zoom, 3, 10) : 5), [zoom]);

  // Fetch latest frame time initially + periodically
  useEffect(() => {
    alive.current = true;
    async function fetchTime() {
      try {
        const r = await fetch("https://api.rainviewer.com/public/weather-maps.json", { cache: "no-store" });
        const j = await r.json();
        const latest = j?.radar?.past?.at(-1)?.time ?? j?.radar?.nowcast?.[0]?.time ?? null;
        if (alive.current && latest) {
          setFrameTime((prev) => (prev !== latest ? latest : prev));
          setTileError(false);
        }
      } catch {/* soft-fail */}
    }
    fetchTime();
    const id = setInterval(fetchTime, Math.max(15, refreshSeconds) * 1000);
    return () => { alive.current = false; clearInterval(id); };
  }, [refreshSeconds]);

  const effectiveTime = useMemo(() => {
    if (typeof frameTime === "number") return frameTime;
    return Math.floor(Date.now() / (10 * 60 * 1000)) * (10 * 60); // seconds
  }, [frameTime]);

  const radarUrl = useMemo(
    () => `https://tilecache.rainviewer.com/v2/radar/${effectiveTime}/256/{z}/{x}/{y}/2/1_1.png`,
    [effectiveTime]
  );

  // Enable/disable map handlers based on hover/toggle
  const interactive = hovering || controlsOn;
  useEffect(() => {
    const map = mapRef.current;
    if (!map) return;
    // Wheel zoom
    if (interactive) map.scrollWheelZoom.enable(); else map.scrollWheelZoom.disable();
    // Dragging
    if (interactive) map.dragging.enable(); else map.dragging.disable();
    // Double-click zoom
    if (interactive) map.doubleClickZoom.enable(); else map.doubleClickZoom.disable();
    // Touch gestures
    if (interactive) {
      map.touchZoom.enable();
      map.boxZoom.enable();
      map.keyboard.enable();
    } else {
      map.touchZoom.disable();
      map.boxZoom.disable();
      map.keyboard.disable();
    }
  }, [interactive]);

  // Mobile helper: auto-timeout map controls after 15s
  useEffect(() => {
    if (!controlsOn) return;
    const id = setTimeout(() => setControlsOn(false), 15000);
    return () => clearTimeout(id);
  }, [controlsOn]);

  return (
    <div
      className={`relative w-full ${className}`}
      style={{ height }}
      onMouseEnter={() => setHovering(true)}
      onMouseLeave={() => setHovering(false)}
    >
      <MapContainer
        whenCreated={(m) => { mapRef.current = m; }}
        center={safeCenter}
        zoom={safeZoom}
        minZoom={3}
        maxZoom={10}
        style={{ width: "100%", height: "100%", borderRadius: 16, overflow: "hidden" }}
        // Start with controls off; we toggle them via effect above
        scrollWheelZoom={false}
        dragging={false}
        doubleClickZoom={false}
        boxZoom={false}
        keyboard={false}
        touchZoom={false}
        zoomControl={false}
        attributionControl={false}
        zoomAnimation={false}
        fadeAnimation={false}
        markerZoomAnimation={false}
        inertia={false}
        preferCanvas={true}
      >
        {/* faint base so it’s never blank */}
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" opacity={0.3} />
        {/* radar (precip + snow) */}
        <TileLayer
          url={radarUrl}
          opacity={0.9}
          eventHandlers={{
            tileload: () => setTilesLoaded(true),
            load: () => setTilesLoaded(true),
            tileerror: () => setTileError(true),
          }}
          updateWhenIdle={true}
          updateWhenZooming={false}
          keepBuffer={2}
          detectRetina={false}
        />
      </MapContainer>

      {/* Status / controls hint */}
      <div
        className="pointer-events-none absolute right-2 bottom-2 text-xs text-white"
        style={{ backdropFilter: "blur(6px)", background: "rgba(0,0,0,0.35)", padding: "4px 8px", borderRadius: 8 }}
      >
        {interactive ? "Pan & zoom enabled" : "Hover or tap to enable controls"}
      </div>

      {/* Mobile toggle */}
      <button
        type="button"
        onClick={() => setControlsOn((v) => !v)}
        className="absolute left-2 bottom-2 text-xs px-2 py-1 rounded-md"
        style={{
          backdropFilter: "blur(6px)",
          background: controlsOn ? "rgba(128,0,255,0.45)" : "rgba(0,0,0,0.35)",
          color: "white",
          border: "1px solid rgba(255,255,255,0.25)"
        }}
      >
        {controlsOn ? "Disable map controls" : "Enable map controls"}
      </button>

      {/* Loading / error overlay */}
      {(!tilesLoaded || tileError) && (
        <div className="pointer-events-none absolute inset-0 flex items-center justify-center">
          <div style={{
            padding: "6px 10px",
            borderRadius: 10,
            fontSize: 12,
            color: "white",
            backdropFilter: "blur(6px)",
            background: "rgba(0,0,0,0.35)"
          }}>
            {tileError ? "Radar tiles failed—retrying…" : "Loading latest radar…"}
          </div>
        </div>
      )}
    </div>
  );
}
